35	@Slf4j
36	@Service
37	@RequiredArgsConstructor
38	public class EntityServiceImpl implements EntityService {
39	
40	    private final EntityRepository entityRepository;
41	
42	    @Qualifier("IngestionIdService")
43	    private final IdService idService;
44	
45	    private final PlatformTransactionManager transactionManager;
46	    private final MeterRegistry meterRegistry;
47	    private final AtomicInteger markInitLastFailedBatches = new AtomicInteger(0);
48	
49	    @Value("${policy.reprocess.mark-init-batch-size:1000}")
50	    private int markInitBatchSize;
51	
52	    @PostConstruct
53	    public void initMetrics() {
54	        meterRegistry.gauge("policy_reprocess_mark_init_last_failed_batches", markInitLastFailedBatches);
55	    }
56	
57	    @Override
58	    public Entity getById(Long id) {
59	        return entityRepository.findById(id).orElse(null);
60	    }
61	
62	    @Override
63	    public void save(Entity entity) {
64	        if (entity.getId() == null) {
65	            entity.setId(idService.nextId());
66	        }
67	
68	        Instant now = Instant.now();
69	
70	        if (entity.getCreatedAt() == null) {
71	            entity.setCreatedAt(now);
72	        }
73	        if (entity.getUpdatedAt() == null) {
74	            entity.setUpdatedAt(now);
75	        }
76	
77	        entityRepository.save(entity);
78	    }
79	
80	    @Override
81	    public void saveBatch(Collection<Entity> entityList) {
82	        Instant now = Instant.now();
83	
84	        for (Entity e : entityList) {
85	            if (e.getId() == null) {
86	                e.setId(idService.nextId());
87	            }
88	
89	            if (e.getCreatedAt() == null) {
90	                e.setCreatedAt(now);
91	            }
92	            if (e.getUpdatedAt() == null) {
93	                e.setUpdatedAt(now);
94	            }
95	        }
96	        entityRepository.saveAll(entityList);
97	    }
98	
99	    public boolean isInterrupted(long entityId) {
100	        return entityRepository.findById(entityId)
101	                .map(Entity::isInterrupted)
102	                .orElse(false);
103	    }
104	
105	    // Use a separate transaction to guarantee the state update is committed,
106	    // even if the outer transaction fails or is rolled back.
107	    @Transactional(propagation = Propagation.REQUIRES_NEW)
108	    public boolean setInterrupted(Long entityId, boolean interrupted) {
109	        int rows = entityRepository.updateInterrupted(entityId, interrupted, Instant.now());
110	        if (rows == 0) {
111	            log.error("setInterrupted rows=0, id={}, interrupted={}", entityId, interrupted);
112	            return false;
113	        }
114	        return true;
115	    }
116	
117	    public Entity getEntity(Long id) {
118	        return entityRepository.findById(id).orElse(null);
119	    }
120	
121	    /**
122	     * Query database based on entity type + identity
123	     */
124	    public Entity getEntity(IngestionRequest req) {
125	        String type = req.getEntityType();
126	
127	        // HOST
128	        if ("HOST".equalsIgnoreCase(type)) {
129	            String hostIdentity = req.getHostId() + "_" + req.getAdapterId();
130	            return entityRepository
131	                    .findFirstByTypeAndHostIdentity(EntityType.HOST, hostIdentity)
132	                    .orElse(null);
133	        }
134	
135	        // USER_HOST_BINDING
136	        String hostIdentity = req.getHostId() + "_" + req.getAdapterId();
137	        return entityRepository
138	                .findFirstByTypeAndHostIdentityAndUserIdentity(
139	                        EntityType.USER_HOST_BINDING, hostIdentity, req.getUserId()
140	                )
141	                .orElse(null);
142	    }
143	
144	    @Override
145	    public Pagination<Entity> queryFailedEntities(EntityQueryDTO req) {
146	
147	        Specification<Entity> spec = (root, query, cb) -> {
148	            List<Predicate> predicates = new ArrayList<>();
149	
150	            if (req.getStage() != null && !req.getStage().isEmpty()) {
151	                predicates.add(cb.equal(root.get("processingStage"), req.getStage()));
152	            }
153	
154	            if (req.getCode() != null) {
155	                predicates.add(cb.equal(root.get("processingCode"), req.getCode()));
156	            } else {
157	                predicates.add(cb.notEqual(root.get("processingCode"), 0));
158	            }
159	
160	            return cb.and(predicates.toArray(new Predicate[0]));
161	        };
162	
163	        String sortKey = req.getSortKey();
164	        boolean asc = "asc".equalsIgnoreCase(req.getSortOrder());
165	
166	        if (sortKey == null || sortKey.isEmpty()) {
167	            sortKey = "createdAt";
168	        }
169	
170	        String sortProperty;
171	        switch (sortKey) {
172	            case "processingStage":
173	                sortProperty = "processingStage";
174	                break;
175	            case "type":
176	                sortProperty = "type";
177	                break;
178	            case "createdAt":
179	            default:
180	                sortProperty = "createdAt";
181	                break;
182	        }
183	
184	        Sort sort = Sort.by(asc ? Sort.Direction.ASC : Sort.Direction.DESC, sortProperty);
185	        Pageable pageable = PageRequest.of(
186	                Math.max(0, req.getPageNum() - 1),
187	                req.getPageSize(),
188	                sort
189	        );
190	
191	        Page<Entity> page = entityRepository.findAll(spec, pageable);
192	
193	        return Pagination.<Entity>builder()
194	                .list(page.getContent())
195	                .totalRecords(page.getTotalElements())
196	                .totalPages(page.getTotalPages())
197	                .pageNum(page.getNumber() + 1)
198	                .pageSize(page.getSize())
199	                .build();
200	    }
201	
202	    @Override
203	    public boolean isProcessingFinished(Long entityId) {
204	        Entity e = entityRepository.findById(entityId).orElse(null);
205	        if (e == null) {
206	            return true;
207	        }
208	
209	        if ("ENFORCED".equalsIgnoreCase(e.getProcessingStage())) {
210	            return true;
211	        }
212	
213	        // processingCode != 0: indicates failure and exit
214	        Integer code = e.getProcessingCode();
215	        return code != null && code != 0;
216	    }
217	
218	    @Override
219	    @Transactional(propagation = Propagation.REQUIRES_NEW)
220	    public boolean updateProcessingState(Entity fresh) {
221	        if (fresh == null || fresh.getId() == null) return false;
222	
223	        fresh.setUpdatedAt(Instant.now());
224	
225	        int rows = entityRepository.updateProcessingState(
226	                fresh.getId(),
227	                fresh.isInterrupted(),
228	                fresh.getAttributeFingerprint(),
229	                fresh.getProcessingStage(),
230	                fresh.getProcessingCode(),
231	                fresh.getLastReqVersion(),
232	                fresh.getProcessingResult(),
233	                fresh.getUpdatedAt()
234	        );
235	        if (rows == 0) log.error("updateProcessingState rows=0, id={}, stage={}", fresh.getId(), fresh.getProcessingStage());
236	        return rows > 0;
237	    }
238	
239	    @Override
240	    public List<Entity> findStuckEntities(Duration staleThreshold, int maxCount) {
241	        Instant before = Instant.now().minus(staleThreshold);
242	        var pageable = PageRequest.of(0, maxCount);
243	
244	        Page<Entity> page = entityRepository.findStuckEntities(before, pageable);
245	        List<Entity> result = page.getContent();
246	        if (!result.isEmpty()) {
247	            log.info("findStuckEntities: found {} candidates before={}, threshold={}",
248	                    result.size(), before, staleThreshold);
249	        }
250	        return result;
251	    }
252	
253	    // Mark entities that need reprocessing to INIT in batches, and return total updated rows.
254	    @Override
255	    public MarkForReprocessResult markAllForReprocess() {
256	        int totalUpdated = 0;
257	        int failedBatches = 0;
258	        int failedCount = 0;
259	        String runResult = "success";
260	        Timer.Sample runSample = Timer.start(meterRegistry);
261	
262	        try {
263	            int effectiveBatchSize = Math.max(1, markInitBatchSize);
264	            Pageable pageable = PageRequest.of(0, effectiveBatchSize);
265	
266	            // Requirement: one transaction per update batch to avoid a huge long transaction.
267	            TransactionTemplate batchTx = new TransactionTemplate(transactionManager);
268	            // Always use a new transaction here so each batch update is independent:
269	            // if one batch fails, only that batch rolls back and already committed batches stay committed.
270	            batchTx.setPropagationBehavior(TransactionDefinition.PROPAGATION_REQUIRES_NEW);
271	
272	            long lastId = Long.MIN_VALUE;
273	            while (true) {
274	                List<Long> batchIds = entityRepository.findTopNIdsNeedMarkForReprocess(
275	                        lastId, ReprocessState.INIT, pageable);
276	                if (batchIds.isEmpty()) {
277	                    break;
278	                }
279	
280	                try {
281	                    Integer updated = batchTx.execute(status ->
282	                            entityRepository.markBatchForReprocess(batchIds, ReprocessState.INIT));
283	                    int updatedRows = updated == null ? 0 : updated;
284	                    totalUpdated += updatedRows;
285	                } catch (Exception ex) {
286	                    failedBatches++;
287	                    failedCount += batchIds.size();
288	                    log.error(
289	                            "markAllForReprocess: batch update failed for id range [{} - {}], batchSize={}, continue with next batch",
290	                            batchIds.get(0), batchIds.get(batchIds.size() - 1), batchIds.size(), ex
291	                    );
292	                }
293	
294	                // Move the cursor forward even when one batch fails, to avoid getting stuck retrying the same batch.
295	                lastId = batchIds.get(batchIds.size() - 1);
296	
297	                // Last short page means this run has drained current backlog.
298	                if (batchIds.size() < effectiveBatchSize) {
299	                    break;
300	                }
301	            }
302	
303	            if (failedBatches > 0) {
304	                runResult = "partial_failure";
305	                log.warn("markAllForReprocess: completed with partial failures, updatedCount={}, failedBatches={}",
306	                        totalUpdated, failedBatches);
307	            }
308	            return MarkForReprocessResult.builder()
309	                    .updatedCount(totalUpdated)
310	                    .failedBatches(failedBatches)
311	                    .failedCount(failedCount)
312	                    .build();
313	        } catch (Exception ex) {
314	            runResult = "failed";
315	            log.error("markAllForReprocess: failed unexpectedly, updatedCount={}, failedBatches={}",
316	                    totalUpdated, failedBatches, ex);
317	            throw ex;
318	        } finally {
319	            markInitLastFailedBatches.set(failedBatches);
320	            runSample.stop(markInitRunTimeCost(runResult));
321	        }
322	    }
323	
324	    @Override
325	    public List<Long> findTopNIdsByReprocessState(ReprocessState state, int limit) {
326	        Pageable pageable = PageRequest.of(0, limit);
327	        return entityRepository.findTopNIdsByReprocessState(state, pageable);
328	    }
329	
330	    @Override
331	    public EntityProcessLockInfo findProcessLockInfoById(Long id) {
332	        return entityRepository.findProcessLockInfoById(id).orElse(null);
333	    }
334	
335	    @Override
336	    @Transactional(propagation = Propagation.REQUIRES_NEW)
337	    public boolean claimInitEntityForReprocess(Long id) {
338	        int rows = entityRepository.claimInitEntityForReprocess(id, Instant.now());
339	        return rows > 0;
340	    }
341	
342	    @Override
343	    @Transactional(propagation = Propagation.REQUIRES_NEW)
344	    public boolean updateReprocessStateById(Long id, ReprocessState state) {
345	        int rows = entityRepository.updateReprocessStateById(id, state, Instant.now());
346	        return rows > 0;
347	    }
348	
349	    private Timer markInitRunTimeCost(String result) {
350	        return Timer.builder("policy_reprocess_mark_init_run_seconds")
351	                .tag("result", result)
352	                .register(meterRegistry);
353	    }
354	}
