195	    // ============================================================
196	    //            Filter parts based on includeFields
197	    // ============================================================
198	    private static List<AttributeItem> filterParts(List<AttributeItem> parts, List<String> includes) {
199	
200	        if (includes == null || includes.isEmpty()) {
201	            return parts;
202	        }
203	
204	
205	        Set<String> includeSet =  new HashSet<>();
206	        for (String field : includes) {
207	            if (field == null || field.isBlank()) {
208	                log.warn("[Fingerprint] Empty include field ignored.");
209	                continue;
210	            }
211	            includeSet.add(field);
212	        }
213	
214	        List<AttributeItem> filtered = new ArrayList<>();
215	
216	        // obey the origin order of "parts"，disregard the order of "includes"
217	        for (AttributeItem item : parts) {
218	            if (includeSet.contains(item.key)) {
219	                filtered.add(item);
220	            }
221	        }
222	
223	        return filtered;
224	    }
