231	    private static String sha256(List<AttributeItem> parts) {
232	        String joined = parts.stream()
233	                .map(i -> i.key + "=" + i.value)
234	                .collect(Collectors.joining("|"));
235	        return DigestUtils.sha256Hex(joined);
236	    }
